System.register([],function(e,t){var n,a,o,c,h,r;return{setters:[],execute:function(){a=(e,t,n,a,o,c)=>({id:e,type:"dialogue",speaker:t,speakerKey:n,text:a,sprite:o?{key:o,position:"linmo"===o?"left":"right"}:void 0,effects:c}),o=(e,t,n)=>({id:e,type:"choice",text:t,choices:n,speaker:""}),c=(e,t,n,a,o)=>({id:e,type:"quiz",text:t,quiz:n,onCorrect:a,onWrong:o,speaker:""}),h=(e,t,n,a)=>({id:e,type:"cg",text:t,background:n,speaker:"",cgImage:a}),r=(e,t)=>({id:e,type:"system",text:t,speaker:""}),e("chapter2Script",[(n=(e,t,n)=>({id:e,type:"narration",text:t,speaker:"",background:n}))("ch2-0-0","第2章：DNA样本污染谜案\n\n凌晨3:47。手机在黑暗中震动。","dark"),a("ch2-0-1","王博士","wang","（电话那头，声音异常急促）林墨。立刻来公司。B2层的DNA存储库——有人闯入了。带上你的门禁卡。不要告诉任何人——包括陈阳和林雪。","wang"),n("ch2-0-2","凌晨3点47分。DNA存储库。上一次轮回中，苏菲亚就是在这个时间点出现在DNA存储库附近的。这次——会一样吗？","corridor"),n("ch2-1-0","第7号实验楼大堂——漆黑一片。只有应急灯的绿色微光。电梯显示停在B2层。","corridor"),n("ch2-1-1","电梯到达B2。走廊的灯全灭了。远处DNA存储库的低温冰箱发出微弱的蓝光——透过玻璃门映在走廊地板上，像一滩发光的积水。","dna_storage"),o("ch2-1-2","DNA存储库的玻璃门虚掩着。门禁系统被拆开了——电路板散落在地上。",[{text:"【先检查门禁】蹲下查看被破坏的门禁系统",next:[n("ch2-1-2a","门禁系统的主控芯片被EMP脉冲烧毁，旁路了安全验证。电磁脉冲器——军规级别的设备。入侵者不是普通小偷。","dna_storage"),a("ch2-1-3a","林墨","linmo",'（内心）电磁脉冲器。黑市价格比DNA存储库里所有样品加在一起还贵。入侵者想拿的不是"值钱的东西"——是特定的样本。')],effects:{flag:"checked_door_lock"}},{text:"【推门进去】直接进入DNA存储库",next:[n("ch2-1-2b","一股冷气扑面而来。低温冰箱的门大开着——白色冷雾像瀑布一样倾泻到地板上。","dna_storage")]}]),n("ch2-2-0","整面墙的低温冰箱发出淡蓝色冷光。地面上有明显的圆形鞋套痕迹。一台冰箱门大开着——货架上有几个空位。","dna_storage"),n("ch2-2-1",'你拿起一个空管。标签上写着：PRO-2024-0721 / ND5-WT / Control。\nND5-WT——Wild Type，野生型。\n你翻看货架上的样品清单。在"已取出"一栏中，有一个编号被圈了出来。',"dna_storage"),n("ch2-2-2","PRO-2024-0723 / ND5-G13528A / Subject — 状态：已取出（02:17）\nG13528A。你的突变。有人在找含有你DNA突变的样品。并且——找到了。","dna_storage"),c("ch2-2-3","你在分析入侵者留下的痕迹时，想起了一个关键问题：",{question:"人类线粒体DNA(mtDNA)编码多少个蛋白？它通过什么方式遗传？",options:[{label:"A",text:"37个蛋白；常染色体显性遗传",correct:!1},{label:"B",text:"13个蛋白；严格的母体遗传——精子的线粒体在受精后被泛素化降解",correct:!0},{label:"C",text:"22个蛋白；X连锁遗传",correct:!1},{label:"D",text:"2个蛋白；随机遗传",correct:!1}],explanation:"人类mtDNA约16569bp，编码：13个呼吸链蛋白(ND1-ND6/ND4L/Cyt b/COX1-COX3/ATP6/ATP8)、22个tRNA、2个rRNA(12S/16S)。严格的母体遗传——父系线粒体在受精后被泛素-蛋白酶体系统选择性降解。",knowledgeId:"mtdna_genetics",knowledgeTitle:"线粒体DNA——母体遗传与37个基因"},[n("ch2-2-3c",'你放下空管。ND5——正是mtDNA编码的13个蛋白之一。你的突变改变了ND5中的一个氨基酸——精氨酸→组氨酸。这个微小的改变——让你成为了"完美适配体"。',"dna_storage")],[n("ch2-2-3w","mtDNA——线粒体DNA。13个蛋白，全部是呼吸链核心亚基。你的突变在其中一个——ND5。你需要记住这些。","dna_storage")]),n("ch2-3-0","突然——存储库深处传来一声轻微的金属碰撞声。\n最后一排货架后面——有一个人影。","dna_storage"),o("ch2-3-1","你压低身体，沿着货架摸过去。冷气在脚下翻涌。绕过最后一排货架——",[{text:"【悄悄靠近】逼近声源",next:[h("ch2-3-cg",'应急灯的绿光中，一个穿实验服的人蹲在地上。深红色长发从兜帽边缘散落。翡翠绿眼瞳在相机屏幕的反光中清晰可见。\n\n"……苏菲亚。"',"dna_storage","/images/cg/cg_sophia_confrontation.png"),a("ch2-3-2","苏菲亚","sophia","我知道你会来。王博士通知你的？还是你自己发现的？算了——不重要。既然你来了——我有东西要给你看。","sophia")],effects:{flag:"sophia_caught_dna",affection:{sophia:5}}},{text:'【出声警告】"谁在那里？"',next:[n("ch2-3-1a","那人影猛地转身——实验服兜帽落下——深红长发在应急灯绿光中如火焰般散开。苏菲亚。她手中微型相机屏幕还亮着——正在传输数据。","dna_storage"),a("ch2-3-1a-d","苏菲亚","sophia","（翡翠绿眼瞳中闪过一丝意外——然后迅速恢复冷静）……你比我想象的警觉。也好——既然被你发现了——不如直接谈。","sophia")],effects:{flag:"confronted_sophia",affection:{sophia:3}}}]),a("ch2-3-3","苏菲亚","sophia",'今天凌晨我收到的指令。来自盖亚协议总部。\n"确认适配体身份后——立刻销毁所有含目标DNA的样本。不要留下任何可供DARPA进行体外适配体培养的生物材料。"\n"若无法安全销毁——执行备用方案——标记适配体本人。"',"sophia"),a("ch2-3-4","林墨","linmo",'"标记适配体本人"——是什么意思？'),a("ch2-3-5","苏菲亚","sophia","意思是——如果我无法销毁你的DNA样本，我就必须向盖亚协议报告你的确切身份、位置和基因型。然后他们会派人来——把你关在一个谁都不知道的地方。活着——但永远不能离开。","sophia"),n("ch2-3-6","她的声音很平静。但她握着微型录音器的手指关节泛白了。","dna_storage"),o("ch2-3-7","苏菲亚看着你。冷柜的蓝光在她脸上投下明暗交错的影子。",[{text:'【追问】"那你为什么还没报告？"',next:[a("ch2-3-7a","苏菲亚","sophia","因为Emma。我的女儿。八岁。Leigh综合征——线粒体DNA ATP6基因T8993G突变。呼吸链复合体V缺陷。医生说——她大概还有两年。","sophia"),a("ch2-3-7b","苏菲亚","sophia","QZ-酶的铁硫簇结构——可以插入哺乳动物线粒体呼吸链中——补偿缺陷亚基的功能。如果我能得到你的DNA序列——我就能设计靶向线粒体的蛋白递送系统——修好我女儿的呼吸链。","sophia"),n("ch2-3-7c","她从领口拉出吊坠项链。翻开——里面是一张小女孩的照片。棕色卷发，笑容灿烂。但面色苍白——眼睛下有明显的黑眼圈。","dna_storage")],effects:{flag:"sophia_emma_revealed",affection:{sophia:15}}},{text:'【冷静】"你需要我做什么？"',next:[a("ch2-3-7d","苏菲亚","sophia","（愣了一下——她没有预料到这个问题）\n……我需要你的信任。不是张总的。是你的。","sophia")],effects:{affection:{sophia:10}}}]),n("ch2-4-0","清晨。B2临时分析区。王博士、林雪、陈阳都已经到了。气氛沉重。","b1_lab"),a("ch2-4-1","王博士","wang","被破坏的样品有一个共同特征——在凝胶电泳上，它们都显示出≈1.2kb的异常条带。","wang"),a("ch2-4-2","林雪","linxue","这条带不是质粒DNA——是线粒体基因片段。我建议做Southern杂交确认。","linxue"),c("ch2-4-3","林雪已经在准备转膜装置。她一边操作一边讲解——像是在教一个必须教会的人。",{question:"Southern杂交检测的是哪种分子？与之对应的Northern杂交和Western杂交呢？",options:[{label:"A",text:"Southern=DNA, Northern=RNA, Western=蛋白质",correct:!0},{label:"B",text:"Southern=RNA, Northern=DNA, Western=脂类",correct:!1},{label:"C",text:"三种都是检测DNA的，只是方法不同",correct:!1},{label:"D",text:"Southern=蛋白质, Northern=DNA, Western=RNA",correct:!1}],explanation:'Southern blot由Edwin Southern于1975年发明，检测DNA（碱变性→转膜→与标记探针杂交）。Northern blot检测RNA。Western blot检测蛋白质（用抗体而非核酸探针）。命名是一个分子生物学幽默——"Southern"是发明者的姓，不是方位词，但后来的RNA和蛋白blot被戏称为"Northern"和"Western"。',knowledgeId:"southern_blot",knowledgeTitle:"Southern/Northern/Western杂交——分子生物学的三大blot技术"},[a("ch2-4-3c","林雪","linxue","对。Southern=DNA。记住了。","linxue",{affection:{linxue:3}})],[a("ch2-4-3w","林雪","linxue","Southern=DNA。Northern=RNA。Western=蛋白。这是分子生物学最基础的三个blot。回去把步骤画一遍。","linxue")]),n("ch2-4-4","两小时后。显影完成。","b1_lab"),a("ch2-4-5","林雪","linxue","结果出来了。1.2kb条带——是线粒体DNA的MT-ND5基因片段。包含——第13528位点。","linxue"),n("ch2-4-6","她抬起头看了你一眼。那个眼神只有一瞬——但你看懂了。她在说：是你。","b1_lab"),a("ch2-4-7","小雅","xiaoya","BLAST结果出来了~1.2kb片段——和人类mtDNA参考序列比对——覆盖率99.7%。但在这个位置——13528位点——参考序列是G——样品是A。G→A。非同义突变。精氨酸→组氨酸。","xiaoya"),a("ch2-4-8","小雅","xiaoya","（声音压得很低，低到只有你和林雪能听到）这是——你的突变。对吧？","xiaoya"),n("ch2-4-9","林雪和小雅同时看着你。陈阳在稍远处听到了——手里的移液器悬在半空。王博士推了推眼镜——什么都没说。","b1_lab"),o("ch2-4-10",'所有人的目光都落在你身上。不是"同事看同事"的目光——更像是"实验者看实验结果"。',[{text:'【坦诚承认】"是的。我在前公司做过全基因组测序。MT-ND5 G13528A突变。"',next:[n("ch2-4-10a","林雪的手指在实验台上停了一秒。陈阳放下了移液器。小雅把键盘推开了——这是她第一次主动把手指从键盘上移开。","b1_lab")],effects:{flag:"admitted_dna",affection:{linxue:10,chenyang:10,xiaoya:10,wang:10}}},{text:'【反客为主】"为什么公司会有我的DNA样本？我从来没在这里抽过血。"',next:[a("ch2-4-10b","王博士","wang","（终于开口了——声音很低）你的DNA样本——不是你入职之后采集的。它来自你前公司华大基因的员工体检数据库。张总通过离岸数据分析公司购买了数据库访问权限。他在你来面试之前——就已经确定了你是适配体。","wang"),n("ch2-4-10c","整个实验室安静了。只有低温冰箱的压缩机在响。你的面试。你的被开除。你来普罗米修斯——全都是被设计好的。","b1_lab")],effects:{flag:"questioned_dna_origin",affection:{wang:15}}}]),n("ch2-5-0","深夜。天台。陈阳一个人站在栏杆旁。远处城市的灯光在闪烁。","rooftop_night"),o("ch2-5-1","他听到脚步声——没有回头——但他知道是谁。他递过一罐咖啡。",[{text:'【安慰】"不管是不是被设计的——你拒绝在儿童药里掺假是真的。那个选择是你做的。"',next:[a("ch2-5-1a","陈阳","chenyang",'（愣了一秒——然后笑了——不是防护性的笑）你说得对。就算所有条件都是被控制的——那个"拒绝"的瞬间——是我自己的。从今天开始——我不再是"被安排"的化学试剂。我是——我自己的催化剂。',"chenyang")],effects:{affection:{chenyang:15}}},{text:'【共鸣】"我也在想同样的问题。我不知道怎么回答你。"',next:[a("ch2-5-1b","陈阳","chenyang","（沉默了很久——然后举起咖啡罐）那我们一起想。两个人想——总比一个人快。","chenyang")],effects:{affection:{chenyang:10}}}]),n("ch2-6-0","深夜。王博士的办公室。只有一盏台灯亮着。","office"),a("ch2-6-1","王博士","wang","这是你父亲留给你的。他把你DNA的基因检测报告——在你还未出生时做的——寄给了我。他把QZ-酶的所有核心数据分成了五个碎片。五把钥匙，五个守护者。解密的关键——是你的DNA甲基化模式。只有你自己能解密。","wang"),h("ch2-6-cg",'泛黄的信纸上，林远山的手写字迹：\n\n"致我的孩子：\n如果你读到这行字——说明我已经不在。对不起。对不起我没有更早地做那个选择。\n五把钥匙：\n碎片A——活性中心氨基酸序列——林雪。\n碎片B——体外复性条件——陈阳。\n碎片C——抑制剂结合位点——苏菲亚。\n碎片D——计算模拟参数——小雅。\n碎片E——翻译后修饰——王建国。\n永远爱你的父亲，林远山"',"office","/images/cg/cg_wang_last_words.png"),r("ch2-end",'▎第2章完成：DNA样本污染谜案\n\n▎新增知识条目：mtDNA母体遗传 | Southern/Northern/Western杂交\n▎新获道具：林远山遗书（含五碎片加密信息）\n▎好感度结算：根据本章各分支选择动态计算\n▎当前轮回：1/25\n\n▎第3章预告：酶活性消失之谜\n"所有的酶都在装死。它们在等什么？"')])}}});